  1→/**
  2→ * PianoQuest Live — Express + WebSocket server with Gemini Live API.
  3→ *
  4→ * Uses @google/genai SDK live.connect() for Gemini Live sessions.
  5→ */
  6→
  7→import express from "express";
  8→import { createServer } from "http";
  9→import path from "path";
 10→import fs from "fs";
 11→import { WebSocketServer, WebSocket } from "ws";
 12→import type { IncomingMessage } from "http";
 13→import { GoogleGenAI, Modality, type Session } from "@google/genai";
 14→import {
 15→  LIVE_MODEL,
 16→  STORYTELLER_INSTRUCTION,
 17→  buildToolDeclarations,
 18→  executeToolLocally,
 19→  toolCallToVisualEvent,
 20→} from "./agent.js";
 21→
 22→const APP_NAME = "pianoquest";
 23→const STATIC_DIR = path.join(__dirname, "..", "..", "static");
 24→const SHEETS_DIR = path.join(__dirname, "..", "..", "sheets");
 25→
 26→
 27→const NOTE_NAMES = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];
 28→
 29→function midiNoteName(note: number): string {
 30→  const octave = Math.floor(note / 12) - 1;
 31→  return `${NOTE_NAMES[note % 12]}${octave}`;
 32→}
 33→
 34→function describeMidiSnapshot(
 35→  msg: Record<string, unknown>,
 36→): string | null {
 37→  const recentNotes = (msg.recent_notes as Array<Record<string, unknown>>) ?? [];
 38→  const activeNotes = (msg.active_notes as Array<Record<string, unknown>>) ?? [];
 39→  const detectedTechniques = (msg.detected_techniques as unknown[]) ?? [];
 40→  const pedalDown = Boolean(msg.pedal_down);
 41→  const bpm = msg.bpm as number | undefined;
 42→  const score = msg.score as number | undefined;
 43→
 44→  const noteBits: string[] = [];
 45→  for (const item of recentNotes.slice(0, 8)) {
 46→    const note = item.note as number | undefined;
 47→    const velocity = item.velocity as number | undefined;
 48→    if (typeof note === "number") {
 49→      noteBits.push(
 50→        typeof velocity === "number"
 51→          ? `${midiNoteName(note)}@${velocity}`
 52→          : midiNoteName(note)
 53→      );
 54→    }
 55→  }
 56→
 57→  const activeBits: string[] = [];
 58→  for (const item of activeNotes.slice(0, 8)) {
 59→    const note = item.note as number | undefined;
 60→    const velocity = item.velocity as number | undefined;
 61→    if (typeof note === "number") {
 62→      activeBits.push(
 63→        typeof velocity === "number"
 64→          ? `${midiNoteName(note)}@${velocity}`
 65→          : midiNoteName(note)
 66→      );
 67→    }
 68→  }
 69→
 70→  const hasPerformanceSignal = recentNotes.length > 0 || activeNotes.length > 0 || pedalDown;
 71→  if (!hasPerformanceSignal) return null;
 72→
 73→  const details: string[] = [];
 74→  if (noteBits.length > 0) details.push("recent notes: " + noteBits.join(", "));
 75→  if (activeBits.length > 0) details.push("currently held: " + activeBits.join(", "));
 76→  details.push(pedalDown ? "sustain pedal is down" : "sustain pedal is up");
 77→  if (bpm) details.push(`target tempo ${bpm} BPM`);
 78→  if (score !== undefined) details.push(`current technique score ${score}`);
 79→  if (detectedTechniques.length > 0) {
 80→    details.push(
 81→      "detected techniques: " + detectedTechniques.slice(0, 6).map(String).join(", ")
 82→    );
 83→  }
 84→
 85→  if (details.length === 0) return null;
 86→
 87→  return (
 88→    "MIDI performance update from the digital piano. " +
 89→    details.join(". ") +
 90→    ". Use this instead of piano microphone audio for note, timing, and dynamics analysis."
 91→  );
 92→}
 93→
 94→// =========================================================================
 95→// Spectator broadcasting — spectators receive all output but send nothing
 96→// =========================================================================
 97→
 98→const spectators = new Set<WebSocket>();
 99→
100→function broadcastSpectators(data: Buffer | string, binary = false) {
101→  for (const s of spectators) {
102→    if (s.readyState === WebSocket.OPEN) {
103→      try { s.send(data, { binary }); } catch {}
104→    }
105→  }
106→}
107→
108→// =========================================================================
109→// Device management types
110→// =========================================================================
111→
112→interface DeviceRoles {
113→  mic: boolean;
114→  midi: boolean;
115→}
116→
117→interface Device {
118→  id: string;
119→  ws: WebSocket;
120→  name: string;
121→  deviceType: "desktop" | "tablet" | "phone" | "unknown";
122→  isPrimary: boolean;
123→  roles: DeviceRoles;
124→  connectedAt: number;
125→}
126→
127→interface RoomSession {
128→  sendRealtimeInput: (input: any) => void;
129→  sendClientContent: (content: any) => void;
130→  primaryWs: WebSocket;
131→  /** All devices in this room */
132→  devices: Map<string, Device>;
133→  /** Accumulated MIDI notes for periodic Gemini snapshots */
134→  midiBuffer: Array<{ note: number; velocity: number; event: string; timestampMs: number }>;
135→  midiFlushTimer: ReturnType<typeof setTimeout> | null;
136→}
137→
138→const rooms = new Map<string, RoomSession>();
139→
140→function generateRoomCode(): string {
141→  const chars = "REDACTED";
142→  let code = "";
143→  const arr = new Uint8Array(4);
144→  require("crypto").randomFillSync(arr);
145→  for (let i = 0; i < 4; i++) {
146→    code += chars[arr[i] % chars.length];
147→  }
148→  return code;
149→}
150→
151→function randomHex(bytes: number): string {
152→  const arr = new Uint8Array(bytes);
153→  require("crypto").randomFillSync(arr);
154→  return Buffer.from(arr).toString("hex");
155→}
156→
157→// =========================================================================
158→// Device detection from User-Agent
159→// =========================================================================
160→
161→function detectDeviceType(req: IncomingMessage): "desktop" | "tablet" | "phone" | "unknown" {
162→  const ua = (req.headers["user-agent"] || "").toLowerCase();
163→  if (ua.includes("ipad") || (ua.includes("android") && !ua.includes("mobile"))) return "tablet";
164→  if (ua.includes("iphone") || ua.includes("android")) return "phone";
165→  if (ua.includes("windows") || ua.includes("macintosh") || ua.includes("linux")) return "desktop";
166→  return "unknown";
167→}
168→
169→function deviceTypeIcon(type: string): string {
170→  switch (type) {
171→    case "desktop": return "💻";
172→    case "tablet": return "📱";
173→    case "phone": return "📷";
174→    default: return "🔲";
175→  }
176→}
177→
178→function deviceTypeName(type: string): string {
179→  switch (type) {
180→    case "desktop": return "Desktop";
181→    case "tablet": return "Tablet";
182→    case "phone": return "Phone";
183→    default: return "Device";
184→  }
185→}
186→
187→// =========================================================================
188→// Room broadcasting — send to all devices in a room + spectators
189→// =========================================================================
190→
191→function broadcastToRoom(room: RoomSession, data: Buffer | string, binary = false) {
192→  for (const device of room.devices.values()) {
193→    if (device.ws.readyState === WebSocket.OPEN) {
194→      try { device.ws.send(data, { binary }); } catch {}
195→    }
196→  }
197→  broadcastSpectators(data, binary);
198→}
199→
200→function sendDeviceList(room: RoomSession) {
201→  const list = Array.from(room.devices.values()).map((d) => ({
202→    id: d.id,
203→    name: d.name,
204→    deviceType: d.deviceType,
205→    isPrimary: d.isPrimary,
206→    roles: { ...d.roles },
207→    connectedAt: d.connectedAt,
208→  }));
209→  const msg = JSON.stringify({ type: "device_list", devices: list });
210→  // Send to all devices so everyone can see the roster
211→  for (const device of room.devices.values()) {
212→    if (device.ws.readyState === WebSocket.OPEN) {
213→      try { device.ws.send(msg); } catch {}
214→    }
215→  }
216→}
217→
218→function setDeviceRole(
219→  room: RoomSession,
220→  deviceId: string,
221→  role: keyof DeviceRoles,
222→  enabled: boolean
223→) {
224→  const device = room.devices.get(deviceId);
225→  if (!device) return;
226→
227→  if (enabled) {
228→    // Exclusive: disable this role on all other devices
229→    for (const d of room.devices.values()) {
230→      if (d.id !== deviceId && d.roles[role]) {
231→        d.roles[role] = false;
232→        // Notify the device that lost the role
233→        if (d.ws.readyState === WebSocket.OPEN) {
234→          try {
235→            d.ws.send(JSON.stringify({
236→              type: "role_assigned",
237→              roles: { ...d.roles },
238→            }));
239→          } catch {}
240→        }
241→      }
242→    }
243→  }
244→
245→  device.roles[role] = enabled;
246→
247→  // Notify the device that got/lost the role
248→  if (device.ws.readyState === WebSocket.OPEN) {
249→    try {
250→      device.ws.send(JSON.stringify({
251→        type: "role_assigned",
252→        roles: { ...device.roles },
253→      }));
254→    } catch {}
255→  }
256→
257→  // Broadcast updated device list
258→  sendDeviceList(room);
259→}
260→
261→// =========================================================================
262→// Express + WebSocket server
263→// =========================================================================
264→
265→export function createApp() {
266→  const app = express();
267→  const server = createServer(app);
268→  const wssDialog = new WebSocketServer({ noServer: true });
269→  const wssSpectator = new WebSocketServer({ noServer: true });
270→  const wssMidi = new WebSocketServer({ noServer: true });
271→  const wssSession = new WebSocketServer({ noServer: true });
272→
273→  app.get("/health", (_req, res) => {
274→    res.json({
275→      status: "ok",
276→      service: APP_NAME,
277→      modes: ["storyteller"],
278→      spectators: spectators.size,
279→      rooms: rooms.size,
280→    });
281→  });
282→
283→  app.get("/", (_req, res) => {
284→    res.sendFile(path.join(STATIC_DIR, "index.html"));
285→  });
286→
287→  app.use("/static", express.static(STATIC_DIR));
288→  app.use("/sheets", express.static(SHEETS_DIR));
289→
290→  // List sheet music files as a tree
291→  app.get("/api/sheets", (_req, res) => {
292→    function walkDir(dir: string, prefix: string): any[] {
293→      const entries: any[] = [];
294→      if (!fs.existsSync(dir)) return entries;
295→      for (const name of fs.readdirSync(dir).sort()) {
296→        const full = path.join(dir, name);
297→        const rel = prefix ? `${prefix}/${name}` : name;
298→        const stat = fs.statSync(full);
299→        if (stat.isDirectory()) {
300→          entries.push({ name, path: rel, type: "folder", children: walkDir(full, rel) });
301→        } else if (name.endsWith(".json")) {
302→          entries.push({ name: name.replace(".json", ""), path: rel, type: "file" });
303→        }
304→      }
305→      return entries;
306→    }
307→    res.json(walkDir(SHEETS_DIR, ""));
308→  });
309→
310→  server.on("upgrade", (request: IncomingMessage, socket, head) => {
311→    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
312→    if (url.pathname === "/ws/session") {
313→      wssSession.handleUpgrade(request, socket, head, (ws) => {
314→        (ws as any)._req = request;
315→        (ws as any)._room = url.searchParams.get("room") ?? "";
316→        (ws as any)._roleHint = url.searchParams.get("role") ?? "";
317→        wssSession.emit("connection", ws, request);
318→      });
319→    } else if (url.pathname === "/ws/dialog") {
320→      wssDialog.handleUpgrade(request, socket, head, (ws) => {
321→        wssDialog.emit("connection", ws, request);
322→      });
323→    } else if (url.pathname === "/ws/spectator") {
324→      wssSpectator.handleUpgrade(request, socket, head, (ws) => {
325→        wssSpectator.emit("connection", ws, request);
326→      });
327→    } else if (url.pathname === "/ws/midi") {
328→      const room = url.searchParams.get("room") ?? "";
329→      wssMidi.handleUpgrade(request, socket, head, (ws) => {
330→        (ws as any)._room = room;
331→        wssMidi.emit("connection", ws, request);
332→      });
333→    } else {
334→      socket.destroy();
335→    }
336→  });
337→
338→  // -----------------------------------------------------------------
339→  // /ws/session — Unified device management endpoint
340→  // -----------------------------------------------------------------
341→
342→  wssSession.on("connection", (ws: WebSocket) => {
343→    const req = (ws as any)._req as IncomingMessage;
344→    const roomCode = (ws as any)._room as string;
345→    const roleHint = (ws as any)._roleHint as string;
346→    const devType = detectDeviceType(req);
347→
348→    if (!roomCode) {
349→      // No room code — this is a new primary device
350→      handlePrimaryWebSocket(ws, req);
351→    } else {
352→      // Room code provided — join as secondary
353→      const room = rooms.get(roomCode);
354→      if (!room) {
355→        console.log(`[${APP_NAME}] Session rejected — room "${roomCode}" not found`);
356→        ws.send(JSON.stringify({ type: "error", message: `Room "${roomCode}" not found` }));
357→        ws.close();
358→        return;
359→      }
360→      handleSecondaryWebSocket(ws, room, roomCode, devType, roleHint);
361→    }
362→  });
363→
364→  // -----------------------------------------------------------------
365→  // /ws/dialog — Legacy primary endpoint (backwards compat)
366→  // -----------------------------------------------------------------
367→
368→  wssDialog.on("connection", (ws: WebSocket, req: IncomingMessage) => {
369→    handlePrimaryWebSocket(ws, req);
370→  });
371→
372→  wssSpectator.on("connection", (ws: WebSocket) => {
373→    console.log(`[${APP_NAME}] Spectator connected (total: ${spectators.size + 1})`);
374→    spectators.add(ws);
375→    ws.on("close", () => {
376→      spectators.delete(ws);
377→      console.log(`[${APP_NAME}] Spectator disconnected (total: ${spectators.size})`);
378→    });
379→    ws.on("error", () => {
380→      spectators.delete(ws);
381→    });
382→  });
383→
384→  // -----------------------------------------------------------------
385→  // /ws/midi — Ubuntu bridge forwards MIDI events to Gemini + iPad
386→  // -----------------------------------------------------------------
387→
388→  function flushMidiToGemini(roomSession: RoomSession) {
389→    if (roomSession.midiBuffer.length === 0) return;
390→
391→    const recentNotes = roomSession.midiBuffer
392→      .filter((m) => m.event === "noteOn")
393→      .slice(-8)
394→      .map((m) => ({ note: m.note, velocity: m.velocity }));
395→
396→    const activeNotes: Array<{ note: number; velocity: number }> = [];
397→    const noteOnMap = new Map<number, number>();
398→    for (const m of roomSession.midiBuffer) {
399→      if (m.event === "noteOn") {
400→        noteOnMap.set(m.note, m.velocity);
401→      } else if (m.event === "noteOff") {
402→        noteOnMap.delete(m.note);
403→      }
404→    }
405→    for (const [note, velocity] of noteOnMap) {
406→      activeNotes.push({ note, velocity });
407→    }
408→
409→    const summary = describeMidiSnapshot(
410→      { recent_notes: recentNotes, active_notes: activeNotes, pedal_down: false },
411→    );
412→
413→    if (summary) {
414→      roomSession.sendClientContent({
415→        turns: [{ role: "user", parts: [{ text: summary }] }],
416→        turnComplete: true,
417→      });
418→    }
419→
420→    roomSession.midiBuffer = [];
421→  }
422→
423→  wssMidi.on("connection", (ws: WebSocket) => {
424→    const room = (ws as any)._room as string;
425→    const roomSession = rooms.get(room);
426→    if (!roomSession) {
427→      console.log(`[${APP_NAME}] MIDI rejected — room "${room}" not found`);
428→      ws.send(JSON.stringify({ type: "error", message: `Room "${room}" not found` }));
429→      ws.close();
430→      return;
431→    }
432→
433→    console.log(`[${APP_NAME}] MIDI bridge connected to room "${room}"`);
434→    ws.send(JSON.stringify({ type: "midi_connected", room }));
435→
436→    ws.on("message", (data: Buffer | string) => {
437→      if (typeof data !== "string") return;
438→      try {
439→        const msg = JSON.parse(data);
440→        if (msg.type !== "midi") return;
441→
442→        // Forward raw MIDI event to all room devices for waterfall rendering
443→        broadcastToRoom(roomSession, JSON.stringify(msg));
444→
445→        // Buffer for Gemini (flush every 2 seconds)
446→        if (msg.event === "noteOn" || msg.event === "noteOff") {
447→          roomSession.midiBuffer.push({
448→            note: msg.note ?? 0,
449→            velocity: msg.velocity ?? 0,
450→            event: msg.event,
451→            timestampMs: msg.timestampMs ?? Date.now(),
452→          });
453→
454→          if (!roomSession.midiFlushTimer) {
455→            roomSession.midiFlushTimer = setTimeout(() => {
456→              roomSession.midiFlushTimer = null;
457→              flushMidiToGemini(roomSession);
458→            }, 2000);
459→          }
460→        }
461→      } catch {}
462→    });
463→
464→    ws.on("close", () => {
465→      console.log(`[${APP_NAME}] MIDI bridge disconnected from room "${room}"`);
466→      if (roomSession.midiFlushTimer) {
467→        clearTimeout(roomSession.midiFlushTimer);
468→        roomSession.midiFlushTimer = null;
469→        flushMidiToGemini(roomSession);
470→      }
471→    });
472→  });
473→
474→  return server;
475→}
476→
477→// =========================================================================
478→// Async WebSocket message generator
479→// =========================================================================
480→
481→async function* wsMessages(
482→  ws: WebSocket
483→): AsyncGenerator<Buffer | string, void, undefined> {
484→  const queue: (Buffer | string)[] = [];
485→  let resolve: (() => void) | null = null;
486→  let done = false;
487→
488→  ws.on("message", (data: Buffer | string) => {
489→    queue.push(data);
490→    if (resolve) {
491→      resolve();
492→      resolve = null;
493→    }
494→  });
495→
496→  ws.on("close", () => {
497→    done = true;
498→    if (resolve) {
499→      resolve();
500→      resolve = null;
501→    }
502→  });
503→
504→  ws.on("error", () => {
505→    done = true;
506→    if (resolve) {
507→      resolve();
508→      resolve = null;
509→    }
510→  });
511→
512→  while (true) {
513→    if (queue.length > 0) {
514→      yield queue.shift()!;
515→    } else if (done) {
516→      return;
517→    } else {
518→      await new Promise<void>((r) => {
519→        resolve = r;
520→      });
521→    }
522→  }
523→}
524→
525→// =========================================================================
526→// Secondary device handler — joins an existing room
527→// =========================================================================
528→
529→async function handleSecondaryWebSocket(
530→  ws: WebSocket,
531→  room: RoomSession,
532→  roomCode: string,
533→  devType: "desktop" | "tablet" | "phone" | "unknown",
534→  roleHint: string
535→) {
536→  const deviceId = randomHex(4);
537→  const device: Device = {
538→    id: deviceId,
539→    ws,
540→    name: deviceTypeName(devType),
541→    deviceType: devType,
542→    isPrimary: false,
543→    roles: { mic: false, midi: false },
544→    connectedAt: Date.now(),
545→  };
546→
547→  room.devices.set(deviceId, device);
548→  console.log(`[${APP_NAME}] Secondary device ${deviceId} (${devType}) joined room "${roomCode}"`);
549→
550→  // Send identity to the secondary device
551→  ws.send(JSON.stringify({
552→    type: "you_are_secondary",
553→    room: roomCode,
554→    deviceId,
555→    deviceType: devType,
556→  }));
557→
558→  // If role hint provided, auto-assign that role
559→  if (roleHint === "mic" || roleHint === "midi") {
560→    setDeviceRole(room, deviceId, roleHint as keyof DeviceRoles, true);
561→  }
562→
563→  // Broadcast updated device list
564→  sendDeviceList(room);
565→
566→  // Handle incoming messages from secondary
567→  try {
568→    for await (const rawMsg of wsMessages(ws)) {
569→      // Binary = PCM audio (only if this device has mic role)
570→      if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
571→        if (!device.roles.mic) continue;
572→        const data = rawMsg instanceof ArrayBuffer ? new Uint8Array(rawMsg) : rawMsg;
573→        room.sendRealtimeInput({
574→          audio: { data: Buffer.from(data).toString("base64"), mimeType: "audio/pcm;rate=16000" },
575→        });
576→      } else if (typeof rawMsg === "string") {
577→        const msg = JSON.parse(rawMsg);
578→        const msgType = msg.type;
579→
580→        if (msgType === "midi_snapshot" && device.roles.midi) {
581→          const summary = describeMidiSnapshot(msg);
582→          if (summary) {
583→            room.sendClientContent({
584→              turns: [{ role: "user", parts: [{ text: summary }] }],
585→              turnComplete: true,
586→            });
587→          }
588→        } else if (msgType === "midi_event" && device.roles.midi) {
589→          // Forward raw MIDI to all room devices for visualization
590→          broadcastToRoom(room, JSON.stringify(msg));
591→        } else if (msgType === "text") {
592→          room.sendClientContent({
593→            turns: [{ role: "user", parts: [{ text: msg.content as string }] }],
594→            turnComplete: true,
595→          });
596→        } else if (msgType === "device_info") {
597→          // Device sends its name
598→          if (msg.name) device.name = String(msg.name).slice(0, 32);
599→          sendDeviceList(room);
600→        } else if (msgType === "close") {
601→          break;
602→        }
603→      }
604→    }
605→  } catch (e: any) {
606→    console.log(`[${APP_NAME}] Secondary ${deviceId} error:`, e?.message);
607→  } finally {
608→    room.devices.delete(deviceId);
609→    console.log(`[${APP_NAME}] Secondary device ${deviceId} disconnected from room "${roomCode}"`);
610→    sendDeviceList(room);
611→    try { ws.close(); } catch {}
612→  }
613→}
