  var handle = document.getElementById('leftResizeHandle');
  var col = document.getElementById('leftCol');
  var main = document.querySelector('.main');
  if (!handle || !col || !main) return;
  var dragging = false;
  handle.addEventListener('mousedown', function(e) {
