    if (!dragging) return;
    var mainRect = main.getBoundingClientRect();
    var newW = e.clientX - mainRect.left;
    newW = Math.max(160, Math.min(newW, mainRect.width * 0.4));
    // Preserve score column width from current grid
    var scoreCol = document.getElementById('scoreCol');
