// Score panel resize handle
(function() {
  var handle = document.getElementById('scoreResizeHandle');
  var col = document.getElementById('scoreCol');
  var main = document.querySelector('.main');
  if (!handle || !col || !main) return;
  var dragging = false;
  handle.addEventListener('mousedown', function(e) {
    e.preventDefault();
    dragging = true;
    handle.classList.add('dragging');
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
  });
  document.addEventListener('mousemove', function(e) {
    if (!dragging) return;
    var mainRect = main.getBoundingClientRect();
    var newW = mainRect.right - e.clientX;
    newW = Math.max(200, Math.min(newW, mainRect.width * 0.6));
    main.style.gridTemplateColumns = '260px 1fr ' + Math.round(newW) + 'px';
  });
  document.addEventListener('mouseup', function() {
    if (!dragging) return;
    dragging = false;
    handle.classList.remove('dragging');
    document.body.style.cursor = '';
    document.body.style.userSelect = '';
  });
})();

